'use strict';const CONFIG={animations:{duration:300,easing:'cubic-bezier(0.4,0,0.2,1)',reducedMotion:window.matchMedia('(prefers-reduced-motion:reduce)').matches},lazyLoading:{threshold:0.1,rootMargin:'50px'},smoothScroll:{duration:800,easing:'cubic-bezier(0.4,0,0.2,1)',offset:80}};class InteractiveUI{constructor(){this.isInitialized=false;this.observers=new Map();if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>this.init());}else{this.init();}document.addEventListener('i18n:loaded',()=>{this.refreshAriaLabels();});}async init(){try{this.checkBrowserSupport();this.initSmoothScroll();this.initLazyLoading();this.initAnimations();this.initMobileMenu();this.initBreadcrumbs();this.initScrollProgress();this.initBackToTop();this.initFormValidation();this.initSearch();this.initThemeToggle();this.initKeyboardNavigation();this.isInitialized=true;document.body.classList.add('interactive-ui-loaded');console.log('Interactive UI initialized successfully');}catch(error){console.error('Failed to initialize Interactive UI:',error);}}checkBrowserSupport(){const features={'IntersectionObserver':'IntersectionObserver' in window,'MutationObserver':'MutationObserver' in window,'CSSCustomProperties':CSS.supports('color','var(--test)'),'Promise':'Promise' in window,'Fetch':'fetch' in window,'LocalStorage':'localStorage' in window};const unsupported=Object.entries(features).filter(([_,supported])=>!supported).map(([feature])=>feature);if(unsupported.length>0){console.warn('Browser does not support:',unsupported);document.body.classList.add('legacy-browser');}}initSmoothScroll(){const links=document.querySelectorAll('a[href^="#"]:not([href="#"])');links.forEach(link=>{link.addEventListener('click',(e)=>{e.preventDefault();const targetId=link.getAttribute('href');const target=document.querySelector(targetId);if(target){this.smoothScrollTo(target);history.pushState(null,null,targetId);target.setAttribute('tabindex','-1');target.focus();}});});}smoothScrollTo(target){const headerOffset=CONFIG.smoothScroll.offset;const targetPosition=target.getBoundingClientRect().top+window.pageYOffset-headerOffset;window.scrollTo({top:targetPosition,behavior:'smooth'});}initLazyLoading(){if(!('IntersectionObserver' in window)){this.loadAllImages();return;}const imageObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;this.loadImage(img);imageObserver.unobserve(img);}});},CONFIG.lazyLoading);document.querySelectorAll('img[data-src]').forEach(img=>{imageObserver.observe(img);});this.observers.set('images',imageObserver);}loadImage(img){const src=img.getAttribute('data-src');const srcset=img.getAttribute('data-srcset');if(src){img.src=src;}if(srcset){img.srcset=srcset;}img.classList.add('loaded');img.removeAttribute('data-src');img.removeAttribute('data-srcset');}loadAllImages(){document.querySelectorAll('img[data-src]').forEach(img=>{this.loadImage(img);});}initAnimations(){if(CONFIG.animations.reducedMotion){document.body.classList.add('no-animations');return;}if(!('IntersectionObserver' in window)){document.querySelectorAll('.animate-on-scroll').forEach(el=>{el.classList.add('animated');});return;}const animationObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const element=entry.target;const delay=element.getAttribute('data-delay')||0;setTimeout(()=>{element.classList.add('animated');},delay);animationObserver.unobserve(element);}});},{threshold:0.1,rootMargin:'50px'});document.querySelectorAll('.animate-on-scroll').forEach(el=>{animationObserver.observe(el);});this.observers.set('animations',animationObserver);}initMobileMenu(){const menuToggle=document.querySelector('.menu-icon');const nav=document.querySelector('.site-nav');if(!menuToggle||!nav)return;menuToggle.addEventListener('click',()=>{this.toggleMobileMenu();});document.addEventListener('click',(e)=>{if(nav.classList.contains('active')&&!nav.contains(e.target)&&!menuToggle.contains(e.target)){this.closeMobileMenu();}});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&nav.classList.contains('active')){this.closeMobileMenu();}});}toggleMobileMenu(){const nav=document.querySelector('.site-nav');const menuToggle=document.querySelector('.menu-icon');const isActive=nav.classList.toggle('active');menuToggle.classList.toggle('active',isActive);document.body.classList.toggle('menu-open',isActive);menuToggle.setAttribute('aria-expanded',isActive.toString());if(isActive){const firstLink=nav.querySelector('.page-link');if(firstLink){setTimeout(()=>firstLink.focus(),100);}}}closeMobileMenu(){const nav=document.querySelector('.site-nav');const menuToggle=document.querySelector('.menu-icon');nav.classList.remove('active');menuToggle.classList.remove('active');document.body.classList.remove('menu-open');menuToggle.setAttribute('aria-expanded','false');}initBreadcrumbs(){const breadcrumbContainer=document.querySelector('.breadcrumbs');if(breadcrumbContainer){this.generateBreadcrumbs();}}generateBreadcrumbs(){const path=window.location.pathname;const parts=path.split('/').filter(part=>part);if(parts.length<=1)return;const breadcrumbs=[{name:window.t?.('navigation.home')||'Home',url:'/'}];let currentPath='';parts.forEach((part,index)=>{currentPath+='/'+part;const name=this.formatBreadcrumbName(part);const isLast=index===parts.length-1;breadcrumbs.push({name,url:currentPath,isLast});});this.renderBreadcrumbs(breadcrumbs);}formatBreadcrumbName(part){const nameMap={'about':window.t?.('navigation.about')||'About','archive':window.t?.('navigation.archive')||'Archive','categories':window.t?.('navigation.categories')||'Categories','tags':window.t?.('navigation.tags')||'Tags'};return nameMap[part]||part.charAt(0).toUpperCase()+part.slice(1);}renderBreadcrumbs(breadcrumbs){const container=document.querySelector('.breadcrumbs');if(!container)return;const nav=document.createElement('nav');nav.setAttribute('aria-label','Breadcrumb');const ol=document.createElement('ol');ol.className='breadcrumb-list';breadcrumbs.forEach((crumb,index)=>{const li=document.createElement('li');if(crumb.isLast){li.setAttribute('aria-current','page');li.textContent=crumb.name;}else{const link=document.createElement('a');link.href=crumb.url;link.textContent=crumb.name;li.appendChild(link);}ol.appendChild(li);});nav.appendChild(ol);container.appendChild(nav);}initScrollProgress(){const progressBar=document.createElement('div');progressBar.className='reading-progress';progressBar.setAttribute('role','progressbar');progressBar.setAttribute('aria-valuenow','0');progressBar.setAttribute('aria-valuemin','0');progressBar.setAttribute('aria-valuemax','100');document.body.appendChild(progressBar);window.addEventListener('scroll',this.throttle(()=>{const winScroll=document.body.scrollTop||document.documentElement.scrollTop;const height=document.documentElement.scrollHeight-document.documentElement.clientHeight;const scrolled=(winScroll/height)*100;progressBar.style.width=scrolled+'%';progressBar.setAttribute('aria-valuenow',Math.round(scrolled).toString());},50));}initBackToTop(){const button=document.createElement('button');button.className='back-to-top';button.setAttribute('aria-label',window.t?.('accessibility.back_to_top')||'Back to top');button.innerHTML=`<svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="18 15 12 9 6 15"></polyline></svg>`;document.body.appendChild(button);window.addEventListener('scroll',this.throttle(()=>{const showThreshold=300;button.classList.toggle('visible',window.pageYOffset>showThreshold);},100));button.addEventListener('click',()=>{window.scrollTo({top:0,behavior:'smooth'});});}initFormValidation(){const forms=document.querySelectorAll('form[data-validate]');forms.forEach(form=>{form.addEventListener('submit',(e)=>{if(!this.validateForm(form)){e.preventDefault();}});form.querySelectorAll('input,textarea,select').forEach(field=>{field.addEventListener('blur',()=>{this.validateField(field);});});});}validateForm(form){let isValid=true;const fields=form.querySelectorAll('input,textarea,select');fields.forEach(field=>{if(!this.validateField(field)){isValid=false;}});return isValid;}validateField(field){const isValid=field.checkValidity();const errorElement=field.parentNode.querySelector('.error-message');field.classList.toggle('invalid',!isValid);if(!isValid&&errorElement){errorElement.textContent=field.validationMessage;errorElement.style.display='block';}else if(errorElement){errorElement.style.display='none';}return isValid;}initSearch(){const searchInput=document.querySelector('[data-search]');if(!searchInput)return;let searchTimeout;searchInput.addEventListener('input',(e)=>{clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>{this.performSearch(e.target.value);},300);});}async performSearch(query){console.log('Searching for:',query);}initThemeToggle(){const themeToggle=document.querySelector('[data-theme-toggle]');if(!themeToggle)return;const savedTheme=localStorage.getItem('theme')||(window.matchMedia('(prefers-color-scheme:dark)').matches ? 'dark':'light');this.setTheme(savedTheme);themeToggle.addEventListener('click',()=>{const currentTheme=document.documentElement.getAttribute('data-theme');const newTheme=currentTheme==='dark' ? 'light':'dark';this.setTheme(newTheme);});}setTheme(theme){document.documentElement.setAttribute('data-theme',theme);localStorage.setItem('theme',theme);const themeToggle=document.querySelector('[data-theme-toggle]');if(themeToggle){themeToggle.setAttribute('aria-pressed',theme==='dark' ? 'true':'false');}}initKeyboardNavigation(){document.addEventListener('keydown',(e)=>{if(e.altKey&&e.key==='s'){e.preventDefault();const searchInput=document.querySelector('[data-search]');if(searchInput){searchInput.focus();}}if(e.altKey&&e.key==='m'){e.preventDefault();this.toggleMobileMenu();}});}refreshAriaLabels(){const elements=document.querySelectorAll('[aria-label][data-aria-i18n]');elements.forEach(element=>{const key=element.getAttribute('data-aria-i18n');const label=window.t?.(key);if(label){element.setAttribute('aria-label',label);}});}throttle(func,limit){let inThrottle;return function(){const args=arguments;const context=this;if(!inThrottle){func.apply(context,args);inThrottle=true;setTimeout(()=>inThrottle=false,limit);}};}debounce(func,wait){let timeout;return function executedFunction(...args){const later=()=>{clearTimeout(timeout);func(...args);};clearTimeout(timeout);timeout=setTimeout(later,wait);};}destroy(){this.observers.forEach(observer=>{observer.disconnect();});}}window.interactiveUI=new InteractiveUI();if(typeof module!=='undefined'&&module.exports){module.exports=InteractiveUI;}